2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // --- Empty / processing fee baseline ---
7	  it("quote with empty item list returns premium 5 (only the processing fee)", () => {
8	    expect(quote({ items: [], customerYears: 0, previousContracts: 0 })).toBe(5);
9	  });
10	
11	  // --- Base premiums for main items (with processing fee) ---
12	  it("quote for a single plain sword returns premium 105 (100 base + 5 fee)", () => {
13	    expect(
14	      quote({
15	        items: [{ type: "sword" }],
16	        customerYears: 0,
17	        previousContracts: 0,
18	      }),
19	    ).toBe(105);
20	  });
21	  it("quote for a single plain amulet returns premium 65 (60 base + 5 fee)", () => {
22	    expect(
23	      quote({
24	        items: [{ type: "amulet" }],
25	        customerYears: 0,
26	        previousContracts: 0,
27	      }),
28	    ).toBe(65);
29	  });
30	  it.todo("quote for a single plain staff returns premium 85 (80 base + 5 fee)");
31	  it.todo("quote for a single plain potion returns premium 45 (40 base + 5 fee)");
32	
33	  // --- Components and block-of-3 rule ---
34	  it.todo("quote for 2 runes returns premium 55 (50 base + 5 fee)");
35	  it.todo("quote for 3 runes returns premium 65 (60 base block + 5 fee)");
36	  it.todo("quote for 4 runes returns premium 105 (100 base + 5 fee, no block — block requires exactly 3)");
37	  it.todo("quote for 7 runes returns premium 180 (175 base + 5 fee)");
38	  it.todo("quote for 2 runes + 1 moonstone returns premium 80 (75 base + 5 fee, no block: different types)");
39	  it.todo("quote for 3 runes + 3 moonstones returns premium 125 (120 base + 5 fee, two separate blocks)");
40	
41	  // --- Item-specific modifiers ---
42	  it.todo("quote for a cursed sword (steel, ench 3) for newcomer (0 yrs, no previous) returns premium 165");
43	  it.todo("quote for a sword with enchantment exactly 5 applies the high-enchantment surcharge");
44	  it.todo("quote for a sword with enchantment 4 does not apply the high-enchantment surcharge");
45	  it.todo("quote for a cursed sword with enchantment 5 applies both curse and high-enchantment surcharges");
46	
47	  // --- Policy-wide modifiers ---
48	  it.todo("quote for a customer with exactly 2 years applies the 20% loyalty discount");
49	  it.todo("first quote in a scenario applies the 10% first-insurance surcharge");
50	  it.todo("second quote in a scenario applies the 15% follow-up contract discount");
51	
52	  // --- Modifier scope on multi-item policies ---
53	  it.todo("quote for cursed sword + plain amulet: curse surcharge is 50G (50% of cursed item's base, not policy total) → 215G (210 + 5 fee)");
54	
55	  // --- Rounding ---
56	  it.todo("premium calculation yielding 197.5 rounds up to 198 (in MHPCO's favor)");
57	
58	  // --- Integration: long-standing customer's second contract ---
59	  it.todo("quote for cursed sword (steel, ench 7) for 3-yr customer's second quote returns premium 160");
60	
61	  // --- Claim: standard reimbursement ---
62	  it.todo("claim on regular sword (steel, ench 3) with damage 500 → payout 400 (full minus 100 deductible)");
63	  it.todo("claim on a rune (insurance 250, no enchantment/material) with damage 200 → payout 100 (full minus deductible)");
64	
65	  // --- Claim: deductible per damage event ---
66	  it.todo("claim with damage to insured sword (500) and insured amulet (300) → payout 600 (deductible applies once per item)");
67	
68	  // --- Claim: enchantment threshold ---
69	  it.todo("claim on steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
70	
71	  // --- Claim: dragon material ---
72	  it.todo("claim on dragon-material sword ench 5, damage 800 → payout 700 (full reimbursement then deductible)");
73	
74	  // --- Claim: enchantment vs dragon material (50% rule wins) ---
75	  it.todo("claim on dragon-material sword ench 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
76	  it.todo("claim on dragon-material sword ench 8, damage 1000 → payout 400 (high-enchantment clause applies, then deductible)");
77	
78	  // --- Claim: payout rounding ---
79	  it.todo("payout calculation yielding 350.5 rounds down to 350 (in MHPCO's favor)");
80	
81	  // --- Multiple items of the same type ---
82	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
83	  it.todo("dragon attack damaging both swords (two sword entries) treats each as separate damage with own deductible");
84	
85	  // --- Cap ---
86	  it.todo("policy covering sword + amulet has insurance sum 1600 and cap 3200");
87	  it.todo("cap is based on unmodified insurance value: cursed sword has cap 2000 regardless of premium modifiers");
88	  it.todo("policy covering sword + 3 runes has insurance sum 1750 (block discount affects premium only, not insurance sum)");
89	
90	  // --- Cap exhaustion across successive claims ---
91	  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remaining cap 600");
92	  it.todo("sword (cap 2000): second claim 1500 after first → payout 600, remaining cap 0 (reduced to remaining cap)");
93	
94	  // --- Error cases ---
95	  it.todo("quote with unknown item type causes the CLI to exit with non-zero status and error to stderr");
96	  it.todo("claim referencing a damage entry whose item is not in the policy causes non-zero exit and stderr error");
97	  it.todo("claim with more damage entries of a type than insured (e.g. two sword damages, one sword) causes non-zero exit");
98	  it.todo("claim with a damage entry of negative amount causes non-zero exit and stderr error");
99	});
