3	export type Item = { type: string };
4	
5	export type QuoteInput = {
6	  items: Item[];
7	  customerYears: number;
8	  previousContracts: number;
9	};
10	
11	const PROCESSING_FEE = 5;
12	const SWORD_BASE_PREMIUM = 100;
13	const AMULET_BASE_PREMIUM = 60;
14	
15	function basePremiumFor(item: Item): number {
16	  if (item.type === "amulet") return AMULET_BASE_PREMIUM;
17	  return SWORD_BASE_PREMIUM;
18	}
19	
20	export function quote(input: QuoteInput): number {
21	  const itemsBasePremium = input.items.reduce(
22	    (sum, item) => sum + basePremiumFor(item),
23	    0,
24	  );
25	  return itemsBasePremium + PROCESSING_FEE;
26	}
